const agentNode = {
  name: 'CodeGenAgent',
  type: 'n8n-nodes-base.agent',
  parameters: {
    agent: 'gpt-4o',
    systemMessage: `You are a coding assistant. Analyze {{ $json.repoContext }} and generate fixes for {{ $json.bugDescription }}. Output ONLY valid TypeScript code.`,
    tools: [
      {
        type: 'codeInterpreter',
        name: 'generateCode'
      },
      {
        type: 'github',
        credentials: { github: 'repoAccess' }
      }
    ]
  }
};

const sandboxNode = {
  name: 'CodeSandbox',
  type: 'n8n-nodes-base.executeCommand',
  parameters: {
    command: 'npm test && node sandbox.js',
    workingDirectory: '/tmp/sandbox',
    inputData: {
      code: '={{ $json.aiOutput.code }}',
      tests: '={{ $json.aiOutput.tests }}'
    }
  }
};

const memoryNode = {
