    contextFields: ['repoContext', 'previousCode', 'testFailures'],
    sessionId: '={{ $json.conversationId }}',
    maxTokens: 8000
  }
};

const prNode = {
  name: 'CreateVerifiedPR',
  type: 'n8n-nodes-base.github',
