const vexWebhookNode = {
  name: 'VexGuardrails',
  type: 'n8n-nodes-base.webhook',
  parameters: {
    httpMethod: 'POST',
    path: 'vex-verify',
    options: {},
    bodyParameters: {
      parameters: [
        { name: 'code', value: '={{ $json.aiOutput.code }}' },
        { name: 'repoContext', value: '={{ $json.repoContext }}' },
        { name: 'tests', value: '={{ $json.aiOutput.tests }}' }
      ]
    }
  }
};

import { Vex, Policy } from '@vex_dev/sdk';

const policy = new Policy({
  name: 'n8nCodingAssistant',
  verifications: [
    {
      type: 'code_execution',
      test: 'npm test',
      success_codes: [0]
    },
    {
      type: 'security_scan',
      tools: ['semgrep', 'bandit'],
      block_on: ['sql-injection', 'command-injection']
    },
    {
      type: 'pii_detection',
      patterns: ['API_KEY', 'GITHUB_TOKEN'],
      action: 'block'
    },
    {
      type: 'dependency_check',
      max_age_days: 90,
      vuln_threshold: 'medium'
    }
  ]
});

const app = new Vex({ apiKey: process.env.VEX_API_KEY });
app.use(policy);

// n8n webhook handler
export async function verifyCode(req: Request) {
  const { code, repoContext } = await req.json();
  const result = await app.verify({ input: code, context: repoContext });
  return Response.json({ approved: result.pass, report: result });
}

const approvalNode = {
  name: 'RouteByVexResult',
  type: 'n8n-nodes-base.if',
  parameters: {
    conditions: {
      options: {
        caseSensitive: true,
        leftValue: '={{ $json.vexResult.approved }}',
        rightValue: true
      }
    }
  }
};

const errorNode = {
  name: 'VexBlockReport',
  type: 'n8n-nodes-base.respondToWebhook',
  parameters: {
    respondWith: 'JSON',
    responseBody: '={{ JSON.stringify($json.vexResult.report) }}',
    options: { }
  }
};
